            response.headers().get("content-type").unwrap(),
            "text/plain; charset=utf-8"
        );
    }

    #[test]
    fn json_into_response() {
        #[derive(Serialize)]
        struct Data { value: i32 }

        let response = Json(Data { value: 42 }).into_response();
        assert_eq!(response.status(), StatusCode::OK);
        assert_eq!(
            response.headers().get("content-type").unwrap(),
            "application/json"
        );
    }

    #[test]
    fn status_tuple_into_response() {
        let response = (StatusCode::CREATED, "created").into_response();
        assert_eq!(response.status(), StatusCode::CREATED);
    }

    #[test]
    fn redirect_response() {
        let response = Redirect::to("/new").into_response();
        assert_eq!(response.status(), StatusCode::FOUND);
        assert_eq!(response.headers().get("location").unwrap(), "/new");
    }

    #[test]
    fn result_into_response() {
        let ok: Result<&str, AppError> = Ok("success");
        assert_eq!(ok.into_response().status(), StatusCode::OK);

        let err: Result<&str, AppError> = Err(AppError::not_found("missing"));
        assert_eq!(err.into_response().status(), StatusCode::NOT_FOUND);
    }

    #[test]
    fn option_into_response() {
        let some: Option<&str> = Some("found");
        assert_eq!(some.into_response().status(), StatusCode::OK);

        let none: Option<&str> = None;
        assert_eq!(none.into_response().status(), StatusCode::NOT_FOUND);
    }
